content = File.read!("/root/presidential_bridge/lib/presidential_bridge/receipt.ex")

# Replace the inline SVG back with the img tag that has proper dimensions
svg_regex = ~r/<svg class="token-top-logo" viewBox="0 0 6609 1864".*?<\/svg>/s
img_tag = "<img src=\"data:image/svg+xml;base64,\" alt=\"LipaGas Logo\" class=\"token-top-logo\" />"
content = String.replace(content, svg_regex, img_tag)

# Update layout logic
# Instead of hardcoding width to 562, we'll configure wkhtmltopdf to scale using the --zoom flag
content = String.replace(content,
  "w = if is_token_receipt, do: \"562pt\", else: \"360pt\"",
  "w = if is_token_receipt, do: \"375.12pt\", else: \"360pt\""
)
content = String.replace(content,
  "h = if is_token_receipt, do: \"1127pt\", else: \"640pt\"",
  "h = if is_token_receipt, do: \"751.92pt\", else: \"640pt\""
)
content = String.replace(content,
  "--disable-smart-shrinking\",",
  "--disable-smart-shrinking\",\n      \"--zoom\", if(is_token_receipt, do: \"0.66747\", else: \"1.0\"),"
)

# And remove the static --zoom 1.0 from the existing code to prevent duplicate argument
content = String.replace(content, "\n      \"--zoom\", \"1.0\",", "")

File.write!("/root/presidential_bridge/lib/presidential_bridge/receipt.ex", content)
IO.puts("Applied fixes to receipt.ex")
